/**
 * @method
 * @name polymarket#createOrDeriveApiKey
 * @description derives the existing L2 api credentials for the wallet private key, creating them if none exist yet
 * @see https://docs.polymarket.com/developers/CLOB/authentication
 * @param {object} [params] extra parameters specific to the exchange API endpoint
 * @returns {object} the api credentials { apiKey, secret, passphrase }
 */
func (this *PolymarketCore) CreateOrDeriveApiKey(optionalArgs ...any) <-chan any {
	ch := make(chan any)
	go func() any {
		defer close(ch)
		defer ccxt.ReturnPanicError(ch)
		params := ccxt.GetArg(optionalArgs, 0, map[string]any{})
		_ = params
		var creds any = nil

		{
			func(this *PolymarketCore) (ret_ any) {
				defer func() {
					if e := recover(); e != nil {
						if e == "break" {
							return
						}
						ret_ = func(this *PolymarketCore) any {
							// catch block:

							creds = (<-this.CreateApiKey(params))
							ccxt.PanicOnError(creds)
							return nil
						}(this)
					}
				}()
				// try block:

				creds = (<-this.DeriveApiKey(params))
				ccxt.PanicOnError(creds)
				return nil
			}(this)

		}

		ch <- creds
		return nil

	}()
	return ch
}
func (this *PolymarketCore) SetApiCredentials(response any) any {
	//
	//     { "apiKey": "...", "secret": "...", "passphrase": "..." }
	//
	var creds any = map[string]any{
		"apiKey":     this.SafeString2(response, "apiKey", "key"),
		"secret":     this.SafeString(response, "secret"),
		"passphrase": this.SafeString(response, "passphrase"),
	}
	// cache in options rather than the typed apiKey/secret/password fields so the
	// assignment is valid in the struct-based languages (C#/Go/Java)
	ccxt.AddElementToObject(this.Options, "l2ApiKey", ccxt.GetValue(creds, "apiKey"))
	ccxt.AddElementToObject(this.Options, "l2Secret", ccxt.GetValue(creds, "secret"))
	ccxt.AddElementToObject(this.Options, "l2Passphrase", ccxt.GetValue(creds, "passphrase"))
	return creds
}

/**
 * @ignore
 * @method
 * @name polymarket#loadApiCredentials
 * @description ensures L2 api credentials are available for private requests — uses the provided apiKey/secret/password when present, otherwise derives them from the privateKey
 */
func (this *PolymarketCore) LoadApiCredentials() <-chan any {
	ch := make(chan any)
	go func() any {
		defer close(ch)
		defer ccxt.ReturnPanicError(ch)
		// the order signer / L2 POLY_ADDRESS is always the EOA behind the privateKey, so the L2 api key MUST
		// belong to that same EOA — derive it from the privateKey rather than trusting externally supplied
		// creds that may have been issued to a different wallet
		if ccxt.IsTrue(!ccxt.IsEqual(this.PrivateKey, nil)) {
			var alreadyDerived any = this.SafeString(this.Options, "l2ApiKey")
			if ccxt.IsTrue(ccxt.IsEqual(alreadyDerived, nil)) {

				retRes270016 := (<-this.CreateOrDeriveApiKey())
				ccxt.PanicOnError(retRes270016)
			}

			return nil
		}
		var apiKey any = ccxt.Ternary(ccxt.IsTrue((!ccxt.IsEqual(this.ApiKey, nil))), this.ApiKey, this.SafeString(this.Options, "l2ApiKey"))
		var secret any = ccxt.Ternary(ccxt.IsTrue((!ccxt.IsEqual(this.Secret, nil))), this.Secret, this.SafeString(this.Options, "l2Secret"))
		var passphrase any = ccxt.Ternary(ccxt.IsTrue((!ccxt.IsEqual(this.Password, nil))), this.Password, this.SafeString(this.Options, "l2Passphrase"))
		var hasL2 any = ccxt.IsTrue(ccxt.IsTrue((!ccxt.IsEqual(apiKey, nil))) && ccxt.IsTrue((!ccxt.IsEqual(secret, nil)))) && ccxt.IsTrue((!ccxt.IsEqual(passphrase, nil)))
		if ccxt.IsTrue(hasL2) {

			return nil
		}
		panic(ccxt.AuthenticationError(ccxt.Add(this.Id, " requires L2 api credentials (apiKey, secret, password) or a privateKey to derive them")))

	}()
	return ch
}
func (this *PolymarketCore) Ping(client any) any {
	// Polymarket keeps the ws alive with a plain-text "PING" (the server replies "PONG"); the
	// keepAlive interval set in describe.streaming sends it on both the market and user channels
	return "PING"
}
func (this *PolymarketCore) HandleMessage(client any, message any) {
	// Polymarket keeps the ws alive with text PING/PONG (not protocol ping-pong frames), so the
	// client's onPong never fires; refresh client.lastPong here on the "PONG" reply, otherwise the
	// base keepalive treats the connection as stale and times it out after maxPingPongMisses.
	if ccxt.IsTrue(ccxt.IsString(message)) {
		client.(ccxt.ClientInterface).SetLastPong(this.Milliseconds())
		return
	}
	var events any = ccxt.Ternary(ccxt.IsTrue(ccxt.IsArray(message)), message, []any{message})
	for i := 0; ccxt.IsLessThan(i, ccxt.GetArrayLength(events)); i++ {
		var event any = ccxt.GetValue(events, i)
		if ccxt.IsTrue(!ccxt.IsTrue(event) || ccxt.IsTrue(!ccxt.IsObject(event))) {
			continue
		}
		var eventType any = this.SafeString(event, "event_type")
		if ccxt.IsTrue(ccxt.IsEqual(eventType, "book")) {
			this.HandleOrderBookSnapshot(client, event)
		} else if ccxt.IsTrue(ccxt.IsEqual(eventType, "price_change")) {
			this.HandleOrderBookDelta(client, event)
		} else if ccxt.IsTrue(ccxt.IsEqual(eventType, "last_trade_price")) {
			this.HandleTrade(client, event)
		} else if ccxt.IsTrue(ccxt.IsEqual(eventType, "order")) {
			this.HandleOrder(client, event)
		} else if ccxt.IsTrue(ccxt.IsEqual(eventType, "trade")) {
			this.HandleMyTrade(client, event)
		}
	}
}
func (this *PolymarketCore) HandleOrderBookSnapshot(client any, event any) {
	var tokenId any = this.SafeString(event, "asset_id")
	var outcome any = this.TokenIdToSymbol(tokenId)
	if ccxt.IsTrue(ccxt.IsEqual(outcome, nil)) {
		return
	}
	if !ccxt.IsTrue((ccxt.InOp(this.Orderbooks, outcome))) {
		var seededBook any = this.OrderBook(map[string]any{})
		ccxt.AddElementToObject(this.Orderbooks, outcome, seededBook)
	}
	var orderbook any = ccxt.GetValue(this.Orderbooks, outcome)
	var timestamp any = this.ParsePolyTimestamp(this.SafeString(event, "timestamp"))
	var rawBids any = this.SafeList(event, "bids", []any{})
	var rawAsks any = this.SafeList(event, "asks", []any{})
	var bids any = []any{}
	for i := 0; ccxt.IsLessThan(i, ccxt.GetArrayLength(rawBids)); i++ {
		var b any = ccxt.GetValue(rawBids, i)
		ccxt.AppendToArray(&bids, []any{this.SafeNumber(b, "price"), this.SafeNumber(b, "size")})
	}
	var asks any = []any{}
	for j := 0; ccxt.IsLessThan(j, ccxt.GetArrayLength(rawAsks)); j++ {
		var a any = ccxt.GetValue(rawAsks, j)
		ccxt.AppendToArray(&asks, []any{this.SafeNumber(a, "price"), this.SafeNumber(a, "size")})
	}
	var outcomeObj any = this.SafeOutcome(outcome)
	orderbook.(ccxt.OrderBookInterface).Reset(map[string]any{
		"bids":      bids,
		"asks":      asks,
		"timestamp": timestamp,
		"datetime":  this.Iso8601(timestamp),
		"outcome":   outcome,
		"outcomeId": tokenId,
		"market":    this.SafeString(outcomeObj, "market"),
	})
	client.(ccxt.ClientInterface).Resolve(orderbook, ccxt.Add("orderbook::", outcome))
	client.(ccxt.ClientInterface).Resolve(orderbook, ccxt.Add("ticker::", outcome))
}
func (this *PolymarketCore) HandleOrderBookDelta(client any, event any) {
	var timestamp any = this.ParsePolyTimestamp(this.SafeString(event, "timestamp"))
	var changes any = this.SafeList(event, "price_changes", []any{})
	var updated any = map[string]any{}
	for i := 0; ccxt.IsLessThan(i, ccxt.GetArrayLength(changes)); i++ {
		var change any = ccxt.GetValue(changes, i)
		var tokenId any = this.SafeString(change, "asset_id")
		var outcome any = this.TokenIdToSymbol(tokenId)
		if ccxt.IsTrue(ccxt.IsTrue((ccxt.IsEqual(outcome, nil))) || !ccxt.IsTrue((ccxt.InOp(this.Orderbooks, outcome)))) {
			continue
		}
		var orderbook any = ccxt.GetValue(this.Orderbooks, outcome)
		var price any = this.SafeNumber(change, "price")
		var size any = this.SafeNumber(change, "size")
		var isBuy any = ccxt.IsEqual(this.SafeStringUpper(change, "side", ""), "BUY")
		var side any = ccxt.Ternary(ccxt.IsTrue(isBuy), ccxt.GetValue(orderbook, "bids"), ccxt.GetValue(orderbook, "asks"))
		// storeArray([price, size]) inserts/updates or removes (size=0) the level
		var sideRef any = side
		sideRef.(ccxt.IOrderBookSide).StoreArray([]any{price, size})
		ccxt.AddElementToObject(orderbook, "timestamp", timestamp)
		ccxt.AddElementToObject(orderbook, "datetime", this.Iso8601(timestamp))
		ccxt.AddElementToObject(updated, outcome, true)
	}
	var updatedSymbols any = ccxt.ObjectKeys(updated)
	for k := 0; ccxt.IsLessThan(k, ccxt.GetArrayLength(updatedSymbols)); k++ {
		var outcome any = ccxt.GetValue(updatedSymbols, k)
		var orderbook any = ccxt.GetValue(this.Orderbooks, outcome)
		client.(ccxt.ClientInterface).Resolve(orderbook, ccxt.Add("orderbook::", outcome))
		client.(ccxt.ClientInterface).Resolve(orderbook, ccxt.Add("ticker::", outcome))
	}
}
func (this *PolymarketCore) HandleTrade(client any, event any) {
	var tokenId any = this.SafeString(event, "asset_id")
	var outcome any = this.TokenIdToSymbol(tokenId)
	if ccxt.IsTrue(ccxt.IsEqual(outcome, nil)) {
		return
	}
	var timestamp any = this.ParsePolyTimestamp(this.SafeString(event, "timestamp"))
	var price any = this.SafeNumber(event, "price")
	var amount any = this.SafeNumber(event, "size")
	var market any = this.SafeOutcome(tokenId)
	var trade any = this.SafePredictionTrade(map[string]any{
		"id":           this.SafeString(event, "transaction_hash"),
		"info":         event,
		"timestamp":    timestamp,
		"datetime":     this.Iso8601(timestamp),
		"outcome":      outcome,
		"outcomeId":    this.SafeString(market, "outcomeId"),
		"label":        this.SafeString(market, "label"),
		"market":       this.SafeString(market, "market"),
		"order":        nil,
		"type":         nil,
		"side":         this.SafeStringLower(event, "side"),
		"takerOrMaker": "taker",
		"price":        price,
		"amount":       amount,
		"cost":         nil,
		"fee":          nil,
	}, market)
	if !ccxt.IsTrue(this.Trades) {
		this.Trades = map[string]any{}
	}
	var stored any = this.SafeValue(this.Trades, outcome)
	if ccxt.IsTrue(ccxt.IsEqual(stored, nil)) {
		var limit any = this.SafeInteger(this.Options, "tradesLimit", 1000)
		stored = ccxt.NewArrayCache(limit)
		ccxt.AddElementToObject(this.Trades, outcome, stored)
	}
	stored.(ccxt.Appender).Append(trade)
	client.(ccxt.ClientInterface).Resolve(stored, ccxt.Add("trades::", outcome))
}

